#!/usr/bin/perl
use strict;
use warnings FATAL => 'all';
use CGI;
my $cgi = CGI::new();

# Get the redirect URL from the 'next' parameter
my $redirect_url = $cgi->param('next');

if (defined $redirect_url) {
    print "Location: $redirect_url\n\n";
} else {
    # If no redirect URL is provided, send them to the home page or default location
    my $default_url = '/'; 
    print "Location: $default_url\n\n";
